#include<bits/stdc++.h>
using namespace std;
int n;
long long k;
const long long mod=1e9+7;
struct matrix
{
    int a[110][110];
    matrix()
    {
        memset(a,0,sizeof(a));
    }
    friend matrix operator*(const matrix&a,const matrix&b)
    {
        matrix c;
        for(int i=1;i<=n;i++)
        {
            for(int j=1;j<=n;j++)
            {
                for(int k=1;k<=n;k++)
                {
                    c.a[i][j]+=1ll*(a.a[i][k]%mod)*(b.a[k][j]%mod)%mod;
                    c.a[i][j]%=mod;
                }
            }
        }
        return c;
    }
}base,ans;
void fastpow(long long y)
{
    for(int i=1;i<=n;i++)
    {
        ans.a[i][i]=1;
    }
    while(y)
    {
        if(y%2==1)
        {
            ans=ans*base;
        }
        base=base*base;
        y/=2;
    }
}
int main()
{
    scanf("%d%lld",&n,&k);
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=n;j++)
        {
            scanf("%d",&base.a[i][j]);
        }
    }
    fastpow(k);
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=n;j++)
        {
            printf("%d ",ans.a[i][j]);
        }
        printf("\n");
    }
    return 0;
}
